tasks.solution:
#include <iostream>
#include <string>

// Recursive function to reverse a string
std::string reverseString(std::string s) {
    // Base case: if the string is empty or has one character
    if (s.length() <= 1) {
        return s;
    }

    // Recursive step: 
    // Take the last character and append the result of reversing the rest
    return s.back() + reverseString(s.substr(0, s.length() - 1));
}

int main() {
    std::string input;
    if (std::cin >> input) {
        std::cout << reverseString(input) << std::endl;
    }
    return 0;
}
